import{_ as t,c as a,o as r,a1 as o}from"./chunks/framework.DDNAyvCW.js";const n="/assets/hero.Bp2O22Zb.webp",m=JSON.parse('{"title":"Chaterm Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"docs/index.md","filePath":"docs/index.md"}'),i={name:"docs/index.md"};function s(l,e,d,c,u,p){return r(),a("div",null,e[0]||(e[0]=[o('<h1 id="chaterm-documentation" tabindex="-1">Chaterm Documentation <a class="header-anchor" href="#chaterm-documentation" aria-label="Permalink to &quot;Chaterm Documentation&quot;">​</a></h1><p>Chaterm (/tʃɑːtɜːm/) is an AI native terminal built for infrastructure and cloud resource management. It enables engineers to use natural language to perform complex tasks such as deploying services, troubleshooting, and resolving problems.</p><p>With its built-in expert-level knowledge base and powerful proxy reasoning capabilities, Chatem understands your business topology and operational goals. No need to memorize complex commands, syntax, or parameters. simply describe your task objectives in natural language, and Chatem can autonomously plan and execute complex operations across multiple hosts or clusters, including key processes such as code building, service deployment, fault diagnosis, and automatic rollback.</p><p>Powered by long-term memory and team knowledge bases, Chaterm learns team knowledge and user habits. Its goal is to be your intelligent DevOps co-pilot, allowing engineers to complete daily tasks more efficiently through reusable agent skills. Chaterm aims to lower the cognitive barrier associated with different technology stacks, enabling every developer to quickly gain the operational experience and execution capabilities of a senior SRE.</p><p><img src="'+n+'" alt=""></p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><ul><li><strong><a href="/docs/start/downloads/">Download Chaterm</a></strong> -- Install Chaterm on macOS, Windows, or Linux</li><li><strong><a href="/docs/start/quickstart/">Quick Start</a></strong> -- Connect to your first host and run your first AI-assisted command</li><li><strong><a href="/docs/hosts/add-personal">Add a Host</a></strong> -- Register a personal server, bastion host, or router</li><li><strong><a href="/docs/ai/settings/">Configure AI</a></strong> -- Choose your model provider and tune AI behavior</li></ul><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><h3 id="ai-agent" tabindex="-1">AI Agent <a class="header-anchor" href="#ai-agent" aria-label="Permalink to &quot;AI Agent&quot;">​</a></h3><p>The Agent understands the target, autonomously plans, and performs problem analysis and root cause localization across multiple hosts, automatically closing the loop to complete complex process handling.</p><p>Every operation is auditable and traceable, and supports rapid log rollback, making AI automation more secure and reliable in production environments.</p><h3 id="smart-completion" tabindex="-1">Smart completion <a class="header-anchor" href="#smart-completion" aria-label="Permalink to &quot;Smart completion&quot;">​</a></h3><p>Combining user habits, local memory, and the current server context, the Agent recommends the most suitable commands, making terminal input smarter and more efficient.</p><p>Supports cross-device session synchronization and reduces mobile input costs through quick commands and voice interaction, making remote maintenance smoother.</p><h3 id="knowledge-base" tabindex="-1">Knowledge Base <a class="header-anchor" href="#knowledge-base" aria-label="Permalink to &quot;Knowledge Base&quot;">​</a></h3><p>Supports importing technical manuals, internal documents, scripts, and white papers to build a personal maintenance knowledge system.</p><p>Chaterm understands the current infrastructure context and accurately retrieves relevant knowledge to assist in task decision-making and execution.</p><h3 id="agent-skill" tabindex="-1">Agent Skill <a class="header-anchor" href="#agent-skill" aria-label="Permalink to &quot;Agent Skill&quot;">​</a></h3><p>Encapsulates complex maintenance processes into reusable AI skills, achieving structured and reliable automated execution.</p><p>Help teams accumulate operational experience, enabling AI to be applied securely and stably in real production environments.</p><h3 id="plugin-system" tabindex="-1">Plugin System <a class="header-anchor" href="#plugin-system" aria-label="Permalink to &quot;Plugin System&quot;">​</a></h3><p>Through plugin extensions, achieve unified authentication, dynamic authorization, and secure encrypted connections for public cloud servers and Kubernetes.</p><p>Provide a more efficient resource access experience and facilitate centralized infrastructure management.</p><h2 id="popular-pages" tabindex="-1">Popular Pages <a class="header-anchor" href="#popular-pages" aria-label="Permalink to &quot;Popular Pages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Description</th></tr></thead><tbody><tr><td><a href="/docs/terminal/operations/">Terminal Operations</a></td><td>Master split panes, session tabs, and terminal workflows</td></tr><tr><td><a href="/docs/ai/dialogs/">AI Dialog</a></td><td>Learn how to interact with the AI agent effectively</td></tr><tr><td><a href="/docs/ai/llms/">Model List</a></td><td>Browse supported LLM providers and configure your preferred model</td></tr><tr><td><a href="/docs/manage/keys/">Key Management</a></td><td>Manage SSH keys and credentials securely</td></tr><tr><td><a href="/docs/mcp/usage/">MCP Usage Guide</a></td><td>Set up and use MCP servers for extended context</td></tr><tr><td><a href="/docs/skills/usage/">Skills Usage Guide</a></td><td>Create, import, and run operational Skills</td></tr><tr><td><a href="/docs/settings/shortcuts/">Shortcuts</a></td><td>View and customize keyboard shortcuts</td></tr><tr><td><a href="/docs/mobile/quickstart/">Mobile Quick Start</a></td><td>Operate on the go with the Chaterm mobile app</td></tr><tr><td><a href="/docs/contributing/">Contributing Guide</a></td><td>Contribute to Chaterm development</td></tr></tbody></table><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><p>Chaterm offers a free tier and paid plans for teams and enterprises. Review the <a href="/docs/start/pricing/">Pricing page</a> for details on features and limits.</p><h2 id="get-help" tabindex="-1">Get Help <a class="header-anchor" href="#get-help" aria-label="Permalink to &quot;Get Help&quot;">​</a></h2><ul><li>Browse the sidebar to explore all documentation sections.</li><li>Report issues or request features on <a href="https://github.com/chaterm/chaterm" target="_blank" rel="noreferrer">GitHub</a>.</li><li>Contact the team at <a href="mailto:support@chaterm.ai" target="_blank" rel="noreferrer">support@chaterm.ai</a>.</li></ul>',29)]))}const g=t(i,[["render",s]]);export{m as __pageData,g as default};
